fn analyzeInstructionDependencies(
  instructions: array<string>
) -> tuple<number, array<number>>
  // 무관용: Instruction dependency chain 분석
  // Returns: critical path length, dependency chain

  var dependencies = []
  var criticalPath = 0

  for i = 0 to instructions.length()
    let instr = instructions[i]

    // Simple model: writes to register create dependencies
    if instr.contains("write") || instr.contains("store")
      dependencies.append(i)

  if dependencies.length() > 0
    criticalPath = dependencies.length()

  (criticalPath, dependencies)

fn calculateILPScore(
  instructionCount: number,
  criticalPathLength: number,
  issueWidth: number
) -> number
  // 무관용: ILP score 계산 (0-100)
  // ILP = (instructions / critical path) / issue width × 100

  if criticalPathLength == 0
    return 0

  let theoreticalParallelism = (instructionCount as f64) / (criticalPathLength as f64)
  let actualParallelism = theoreticalParallelism / (issueWidth as f64)
  let score = (actualParallelism * 100.0) as number

  if score > 100
    return 100
  else
    return score

fn scheduleInstructions(
  instructions: array<string>,
  reorderBufferSize: number
) -> array<number>
  // 무관용: Instruction scheduling for max ILP
  // Returns: scheduled order

  var scheduled = []
  var robUsage = 0

  for i = 0 to instructions.length()
    if robUsage < reorderBufferSize
      scheduled.append(i)
      robUsage = robUsage + 1
    else
      // Wait for ROB to drain
      robUsage = 1
      scheduled.append(i)

  scheduled

