fn calculateBranchAccuracy(
  predicted: array<bool>,
  actual: array<bool>
) -> f64
  // 무관용: 정확도 > 95%

  if predicted.length() == 0
    return 0.0

  var correct = 0

  for i = 0 to predicted.length()
    if i < actual.length() && predicted[i] == actual[i]
      correct = correct + 1

  (correct as f64) / (predicted.length() as f64)

fn optimizeBranchPatterns(
