  for i = 0 to branchSequence.length()
    if branchSequence[i]
      takenCount = takenCount + 1

  // Highly predictable if >90% same direction
  let ratio = (takenCount as f64) / (branchSequence.length() as f64)
  let accuracy = if ratio > 0.90 || ratio < 0.10 then 0.95 else 0.80

