  var branchSequence = []
  for i = 0 to operations.length() / 10
    branchSequence.append(i % 2 == 0)

  let predictions = predictBranchDirections([], branchSequence)
  let branchAccuracy = calculateBranchAccuracy(predictions, branchSequence)

