fn detectAccessPattern(
  addressSequence: array<number>
) -> string
  // 무관용: Common memory access patterns 감지
  // Sequential, Strided, Random, Looping, etc.

  if addressSequence.length() < 2
    return "unknown"

  let first = addressSequence[0]
  let second = addressSequence[1]
  let stride = second - first

  // Check for sequential pattern (stride == constant)
  var isSequential = true
  for i = 2 to addressSequence.length()
    if i < addressSequence.length()
      let currentStride = addressSequence[i] - addressSequence[i - 1]
      if currentStride != stride
        isSequential = false

  if isSequential && stride > 0
    return "sequential_ascending"
  else if isSequential && stride < 0
    return "sequential_descending"
  else if stride == 0
    return "looping"
  else
    return "irregular"

fn extractPatternFeatures(
  pattern: MemoryAccessPattern
) -> array<f64>
  // 무관용: Pattern을 neural network input으로 변환
  // Features: stride, variance, period, entropy

  var features = []

  // Feature 1: Average stride
  if pattern.addressSequence.length() >= 2
    let stride = (pattern.addressSequence[1] - pattern.addressSequence[0]) as f64
    features.append(stride / 1000.0)  // Normalize
  else
    features.append(0.0)

  // Feature 2: Access rate (addresses per microsecond)
  if pattern.accessTimestamps.length() > 1
    let timeDiff = pattern.accessTimestamps[pattern.accessTimestamps.length() - 1] - pattern.accessTimestamps[0]
    let rate = (pattern.addressSequence.length() as f64) / ((timeDiff as f64) + 1.0)
    features.append(rate)
  else
    features.append(0.0)

  // Feature 3: Pattern confidence
  features.append(pattern.confidence)

  // Feature 4: Read/Write ratio
  var readCount = 0
  for accessType in pattern.accessTypes
    if accessType == "read"
      readCount = readCount + 1

  let readRatio = (readCount as f64) / (pattern.accessTypes.length() as f64)
  features.append(readRatio)

  features

