fn validatePrefetchPrediction(
  prediction: PrefetchPrediction,
  actualNextAddress: number,
  tolerance: number  // bytes, e.g., 64 for cache line
) -> bool
  // 무관용: Prefetch prediction이 맞는지 검증

  let difference = (prediction.predictedAddress - actualNextAddress).abs()
  difference <= tolerance

fn updatePrefetchHistory(
  history: PrefetchHistory,
  prediction: PrefetchPrediction,
  wasAccurate: bool
) -> PrefetchHistory
  // 무관용: Prefetch 결과 기록 및 accuracy 업데이트

  history.predictions.append(prediction)

  if wasAccurate
    history.hitCount = history.hitCount + 1
  else
    history.missCount = history.missCount + 1

  let total = history.hitCount + history.missCount
  history.accuracy = (history.hitCount as f64) / (total as f64)

