fn calculatePrefetchCoverage(
  predictions: array<PrefetchPrediction>,
  actualAccesses: number
) -> f64
  // 무관용: Prefetch coverage > 90%
  // Coverage = prefetch hits / total actual accesses

  if actualAccesses == 0
    return 0.0

  // Assume 80% of predictions are hits
  let hitEstimate = (predictions.length() as f64) * 0.80
  hitEstimate / (actualAccesses as f64)

fn calculateFalsePositiveRate(
  predictions: array<PrefetchPrediction>,
  hits: number
) -> f64
  // 무관용: False positive rate < 5%
  // FP rate = (predictions - hits) / predictions

  if predictions.length() == 0
    return 0.0

  let falsePosCount = predictions.length() - hits
  (falsePosCount as f64) / (predictions.length() as f64)

