// ============================================================================
// Dynamic Batch Size Calculation
// ============================================================================

fn calculateOptimalBatchSize(
  condition: NetworkCondition,
  msgProcessingTimeUs: number,
  maxLatencyBudgetUs: number
) -> number
  // 무관용: Network 조건에 따른 최적 batch size

  // If network is congested, smaller batches
  let congestionFactor = 1.0 - condition.congestionLevel

  // Available time = max latency - current latency
  let availableTimeUs = (maxLatencyBudgetUs - condition.currentLatencyUs) as f64

  if availableTimeUs <= 0.0
    return 1  // Network so slow, can't batch

  // Batch size = available time / per-message processing
  let optimalSize = (availableTimeUs / (msgProcessingTimeUs as f64)) as number
  let adjustedSize = ((optimalSize as f64) * congestionFactor) as number

  if adjustedSize < 1
    return 1
  else if adjustedSize > 128
    return 128
  else
    return adjustedSize

fn calculateOptimalTimeout(
  batchSize: number,
  msgProcessingTimeUs: number,
  networkLatencyUs: number,
  targetLatencyUs: number
) -> number
  // 무관용: Timeout < 100µs (초과하면 지연 증가)

  let processingTimeForBatch = batchSize * msgProcessingTimeUs
  let networkContributionUs = networkLatencyUs / 2  // Round-trip

  let availableTimeUs = targetLatencyUs - networkContributionUs - processingTimeForBatch

  if availableTimeUs < 10
    return 10  // Minimum 10µs
  else if availableTimeUs > 100
    return 100  // Maximum 100µs
  else
    return availableTimeUs

// ============================================================================
// Adaptive Protocol Selection
// ============================================================================

fn selectOptimalProtocol(
  condition: NetworkCondition,
  reliability: string  // "best_effort", "reliable"
) -> string
  // 무관용: Network 조건에 최적인 protocol 선택

  if condition.currentLatencyUs < 500 && reliability == "best_effort"
    return "UDP"  // Low latency, no reliability needed
  else if condition.currentLatencyUs < 300 && condition.packetLossRate < 0.01
    return "RDMA"  // Ultra low latency with RDMA
  else if condition.packetLossRate > 0.01 || reliability == "reliable"
    return "TCP"  // Reliable delivery needed
  else
    return "UDP"  // Default

fn shouldSwitchProtocol(
  currentProtocol: string,
  recommended: string,
  switchingCostUs: number,
  expectedGainUs: number
) -> bool
  // 무관용: Protocol 전환이 이득인지 판단

  if currentProtocol == recommended
    return false

  let roi = (expectedGainUs as f64) / (switchingCostUs as f64)
  roi > 1.5  // 1.5x ROI threshold

