  // 예: Cache(P4) + Network(P3) 동시 적용

  var orchestration = []

  // Sort by priority (descending)
  for i = 0 to decisions.length()
    for j = 0 to (decisions.length() - 1)
      let decision_j = decisions[j]
      let decision_j1 = decisions[j + 1]

      if decision_j.priority < decision_j1.priority
        let temp = decisions[j]
        decisions[j] = decisions[j + 1]
        decisions[j + 1] = temp

  // Apply top 2 optimizations (avoid interference)
  let topN = if decisions.length() > 2 then 2 else decisions.length()

  for i = 0 to topN
    let decision = decisions[i]
    orchestration.append((decision.recommendedLayer, decision.priority))

  orchestration

