fn evaluateParameterChange(
  paramName: string,
  oldValue: number,
  newValue: number,
  oldMetrics: TuningMetrics,
  newMetrics: TuningMetrics
) -> TuningFeedback
  // 무관용: Parameter 변경의 영향도 평가

  let latencyImprovement = ((oldMetrics.latencyUs - newMetrics.latencyUs) as f64) / (oldMetrics.latencyUs as f64)
  let isPositive = latencyImprovement > 0.02  // 2% threshold

  {
    "parameterId": paramName,
    "previousValue": oldValue,
    "newValue": newValue,
    "metricsImprovement": latencyImprovement * 100.0,
    "timestamp": 0,
    "isPositive": isPositive
  }

fn adjustParameterGradient(
  param: number,
  feedback: TuningFeedback,
  learningRate: f64
) -> number
  // 무관용: Gradient descent style parameter update
  // new_param = old_param + learning_rate × improvement × sign

  let sign = if feedback.isPositive then 1.0 else -1.0
  let adjustment = learningRate * (feedback.metricsImprovement / 100.0) * sign
  let newParam = (param as f64) + adjustment * 10.0

  (newParam as number)

fn findOptimalBatchSize(
  networkLatency: number,
  processingTimePerMsg: number,
  maxBatchTime: number
) -> number
  // 무관용: Optimal batch size 계산
  // BatchSize = min(maxBatches, (MaxBatchTime - NetworkLatency) / ProcessingTime)

  if networkLatency >= maxBatchTime
    return 1  // Network too slow, can't batch

  let availableTime = maxBatchTime - networkLatency
  let optimalSize = (availableTime / processingTimePerMsg) as number

  if optimalSize < 1
    return 1
  else if optimalSize > 128
    return 128
  else
    return optimalSize

fn findOptimalPrefetchDistance(
  cpuFrequencyGhz: f64,
  memoryLatencyNs: number,
  cacheLineSize: number
) -> number
  // 무관용: L1 prefetch distance 계산
  // Distance = MemoryLatency / CycleTime

  let cycleTimeNs = 1000.0 / cpuFrequencyGhz
  let distanceCycles = (memoryLatencyNs as f64) / cycleTimeNs
  let distanceLines = ((distanceCycles / 64.0) as number)  // Cycles per cache line fetch

  if distanceLines < 1
    return 1
  else if distanceLines > 10
    return 10
  else
    return distanceLines

// ============================================================================
// Multi-Parameter Optimization
// ============================================================================

fn optimizeParameterSet(
  currentParams: TunableParameters,
  metrics: TuningMetrics
) -> TunableParameters
  // 무관용: 여러 parameter 동시 최적화

  var optimizedParams = currentParams

  // Parameter 1: Cache line size (usually fixed at 64, but explore)
  // Keep at 64 bytes (standard)
  optimizedParams.cacheLineSizeBytes = 64

  // Parameter 2: L1 prefetch distance
  let l1Distance = findOptimalPrefetchDistance(3.5, 4000, 64)
  optimizedParams.l1PrefetchDistance = l1Distance

  // Parameter 3: Message batch size (depends on latency)
  let batchSize = findOptimalBatchSize(100, 2, 100)  // Network 100µs, process 2µs/msg, max 100µs
  optimizedParams.messageBatchSize = batchSize

  // Parameter 4: SIMD width (scale with available resources)
  optimizedParams.simdWidth = 256  // AVX2

  // Parameter 5: ILP window (balance with ROB size)
  optimizedParams.ilpWindow = 32

  optimizedParams

fn trackParameterConvergence(
  history: TuningHistory
) -> tuple<bool, number>
  // 무관용: Parameter tuning이 수렴했는지 추적
  // Converged if: last 10 iterations show <1% change

  if history.feedbacks.length() < 10
    return (false, history.iterationCount)

  var changeSum = 0.0
  for i = (history.feedbacks.length() - 10) to history.feedbacks.length()
    if i < history.feedbacks.length()
      let feedback = history.feedbacks[i]
      changeSum = changeSum + (feedback.metricsImprovement).abs()

  let averageChange = changeSum / 10.0
  let converged = averageChange < 1.0  // Less than 1% change

  (converged, history.iterationCount)

// ============================================================================
// Stability Monitoring
// ============================================================================

fn calculateMetricsVariance(
  recentMetrics: array<TuningMetrics>
) -> f64
  // 무관용: 최근 metrics의 variance 계산
  // Stability = 1 - variance (higher is more stable)

  if recentMetrics.length() == 0
    return 1.0

  // Calculate mean
  var meanLatency = 0.0
  for metrics in recentMetrics
    meanLatency = meanLatency + (metrics.latencyUs as f64)

  meanLatency = meanLatency / (recentMetrics.length() as f64)

  // Calculate variance
  var variance = 0.0
  for metrics in recentMetrics
    let diff = ((metrics.latencyUs as f64) - meanLatency)
    variance = variance + (diff * diff)

  variance = variance / (recentMetrics.length() as f64)
  let stdDev = (variance).sqrt()

  // Stability = 1 - (stdDev / mean)
  let stability = 1.0 - (stdDev / meanLatency)
  if stability < 0.0 then 0.0 else if stability > 1.0 then 1.0 else stability

fn ensureParameterStability(
  params: TunableParameters,
  stability: f64
) -> TunableParameters
  // 무관용: Stability < 99% 면 aggressive tuning 중지

  if stability < 0.99
    // Conservative: revert to previous values
    // (In real system, would restore from history)
    return params
  else
    return params  // All good, keep optimized params

// ============================================================================
// Adaptive Learning Rate
// ============================================================================

fn calculateAdaptiveLearningRate(
  iteration: number,
  convergenceRate: f64
) -> f64
  // 무관용: Learning rate를 동적으로 조정
  // Start high, decay as we converge

  let initialRate = 0.1
  let decayFactor = 0.95  // Decay per iteration
  let finalRate = initialRate * ((decayFactor as f64) ^ (iteration as f64))

  if finalRate < 0.001
    return 0.001  // Minimum learning rate
  else
    return finalRate

// ============================================================================
// Integrated Auto-Tuning
// ============================================================================

fn executeAutoTuningIteration(
  currentParams: TunableParameters,
  history: TuningHistory,
  metrics: TuningMetrics
) -> tuple<TunableParameters, TuningHistory, bool>
  // 무관용: Single auto-tuning iteration

  // Step 1: Optimize parameter set
  let optimizedParams = optimizeParameterSet(currentParams, metrics)

  // Step 2: Evaluate change
  var oldMetrics = TuningMetrics{
    "latencyUs": 850 + history.iterationCount,  // Simulated
    "throughputOpsPerUs": 1.0,
    "cacheHitRate": 0.95,
    "energyPerOp": 35.0,
    "stability": 0.98,
    "converged": false
  }

  let feedback = evaluateParameterChange("batch_size", currentParams.messageBatchSize, optimizedParams.messageBatchSize, oldMetrics, metrics)

  // Step 3: Update history
  var updatedHistory = history
  updatedHistory.parameters.append(optimizedParams)
  updatedHistory.feedbacks.append(feedback)
  updatedHistory.iterationCount = history.iterationCount + 1

  // Step 4: Check convergence
  let (converged, _) = trackParameterConvergence(updatedHistory)
  updatedHistory.convergenceReached = converged

  (optimizedParams, updatedHistory, converged)

