// Reporting
// ============================================================================

fn generateAutoTuningReport(
  history: TuningHistory,
  finalMetrics: TuningMetrics
) -> string
  var report = "=== AUTO-TUNING REPORT ===\\\\n"

  report = report + "\\\\n--- Convergence Progress ---\\\\n"
  report = report + "Iterations: " + (history.iterationCount as string) + " (target < 100)\\\\n"
  report = report + "Converged: " + if history.convergenceReached then "YES ✓" else "IN PROGRESS..." + "\\\\n"

  report = report + "\\\\n--- Performance Improvement ---\\\\n"
  report = report + "Initial Latency: " + (history.bestLatencyUs as string) + "µs\\\\n"
  report = report + "Final Latency: " + (finalMetrics.latencyUs as string) + "µs\\\\n"
  let improvement = ((history.bestLatencyUs - finalMetrics.latencyUs) as f64) / (history.bestLatencyUs as f64) * 100.0
  report = report + "Improvement: " + (improvement as number as string) + "% (target > 10%)\\\\n"
  report = report + "Status: " + if improvement > 10.0 then "✓ PASS" else "⚠️ CONTINUE" + "\\\\n"

  report = report + "\\\\n--- Stability Metrics ---\\\\n"
  report = report + "Stability: " + (finalMetrics.stability * 100.0 as number as string) + "% (target > 99%)\\\\n"
  report = report + "Cache Hit Rate: " + (finalMetrics.cacheHitRate * 100.0 as number as string) + "%\\\\n"
  report = report + "Throughput: " + (finalMetrics.throughputOpsPerUs as string) + " ops/µs\\\\n"

  report
